// Extract step input and determine what to fetch
const item = $input.first().json;
const { resolvedConfig, variableContext, tenantId } = item;

// Pass through for downstream Supabase nodes
return {
  json: {
    ...item,
    templateId: resolvedConfig.template_id || null,
    configuredTo: resolvedConfig.to || null,
    configuredSubject: resolvedConfig.subject || 'Notification',
    configuredHtml: resolvedConfig.html_body || '<p>Notification</p>',
    responseId: variableContext.responseId || null,
  }
};

// =============================================================
// Resolve Variables + Build Email Payload
// =============================================================
// Merges template data, resolves recipient from response chain,
// resolves variables in subject/html, returns final payload.
// =============================================================

function resolveVariables(template, context) {
  if (typeof template !== 'string') return template;
  return template.replace(/\{\{(\s*[\w.]+\s*)\}\}/g, (_, rawKey) => {
    const key = rawKey.trim();
    const value = getNestedValue(context, key);
    return (value !== undefined && value !== null) ? String(value) : `{{${key}}}`;
  });
}

function getNestedValue(obj, path) {
  const parts = path.split('.');
  let current = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined;
    current = current[part];
  }
  return current;
}

try {
  // Get the original input from Extract Input
  const extractInput = $('Extract Input').first().json;
  const { variableContext, tenantId, configuredTo, configuredSubject, configuredHtml, templateId } = extractInput;

  let subject = configuredSubject;
  let html = configuredHtml;

  // Try to get template data
  if (templateId) {
    try {
      const templateItems = $('Fetch Email Template').all();
      if (templateItems.length && templateItems[0].json && templateItems[0].json.html_body) {
        subject = templateItems[0].json.subject || subject;
        html = templateItems[0].json.html_body;
      }
    } catch (e) {
      // Template fetch may have failed — use configured values
    }
  }

  // Determine recipient
  let to = configuredTo;
  if (!to && extractInput.responseId) {
    try {
      const responseItems = $('Fetch Response').all();
      if (responseItems.length && responseItems[0].json && responseItems[0].json.survey_link_id) {
        // We have the survey_link_id — need to fetch survey_link for notification_email
        // Store it for the next Supabase Get node
        return {
          json: {
            ...extractInput,
            subject,
            html,
            to: null,
            surveyLinkId: responseItems[0].json.survey_link_id,
            needsSurveyLinkFetch: true,
          }
        };
      }
    } catch (e) {
      // Response fetch may have failed
    }
  }

  if (!to) throw new Error('No recipient email resolved for send_email step');

  // Resolve variables in subject and html
  subject = resolveVariables(subject, variableContext);
  html = resolveVariables(html, variableContext);

  return {
    json: {
      ...extractInput,
      emailPayload: { to, subject, html, tenant_id: tenantId },
      needsSurveyLinkFetch: false,
    }
  };
} catch (err) {
  const extractInput = $('Extract Input').first().json;
  return {
    json: {
      ...extractInput,
      stepResult: { success: false, error: err.message },
      needsSurveyLinkFetch: false,
    }
  };
}

// Final recipient resolution after survey_link fetch
function resolveVariables(template, context) {
  if (typeof template !== 'string') return template;
  return template.replace(/\{\{(\s*[\w.]+\s*)\}\}/g, (_, rawKey) => {
    const key = rawKey.trim();
    const value = getNestedValue(context, key);
    return (value !== undefined && value !== null) ? String(value) : `{{${key}}}`;
  });
}

function getNestedValue(obj, path) {
  const parts = path.split('.');
  let current = obj;
  for (const part of parts) {
    if (current === null || current === undefined || typeof current !== 'object') return undefined;
    current = current[part];
  }
  return current;
}

try {
  const prev = $('Resolve Variables').first().json;

  // If we already have a payload or error, pass through
  if (prev.emailPayload || prev.stepResult) {
    return { json: prev };
  }

  const surveyLinkItems = $('Fetch Survey Link').all();
  let to = null;
  if (surveyLinkItems.length && surveyLinkItems[0].json && surveyLinkItems[0].json.notification_email) {
    to = surveyLinkItems[0].json.notification_email;
  }

  if (!to) throw new Error('No recipient email resolved for send_email step');

  let subject = resolveVariables(prev.subject, prev.variableContext);
  let html = resolveVariables(prev.html, prev.variableContext);

  return {
    json: {
      ...prev,
      emailPayload: { to, subject, html, tenant_id: prev.tenantId },
    }
  };
} catch (err) {
  const prev = $('Resolve Variables').first().json;
  return {
    json: {
      ...prev,
      stepResult: { success: false, error: err.message },
    }
  };
}

// Build success result after email sent
const item = $('Finalize Recipient').first().json;
return {
  json: {
    stepResult: {
      success: true,
      outputPayload: {
        emailSent: true,
        recipientEmail: item.emailPayload.to,
      },
    },
  }
};

// Pass through error result
const item = $input.first().json;
return {
  json: {
    stepResult: item.stepResult,
  }
};
